"""
MKT Original Language Commentary — Deuteronomy chapters 5–7
Run: python3 scripts/zc-original-deuteronomy-5-7.py

Source data used:
- data/interlinear/deuteronomy.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/deuteronomy.json

Key decisions in this range:
- Ch 5 is the second giving of the Decalogue; where Deut differs from Exod 20, the difference is noted
- v6:4 already exists in the output file (Shema commentary from prior script) — merge_comm will skip it
- רצח (H7523) translated "murder" not "kill" — the verb is specific to unlawful homicide
- חמד (H2530) vs. אוה (H183) in v21 — Deut uses two different covet-verbs, unlike Exod 20:17
- Chapter 6:5 love with three faculties — לב/נפש/מאד treated as a merism for total self
- Chapter 7 election language: אהב (love) as a covenantal, unconditional act before Israel's existence
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUTERONOMY = {
  "5": {
    "1": '<p><strong>שְׁמַע יִשְׂרָאֵל</strong> (<em>shĕmaʿ yiśrāʾēl</em>) — "Hear, O Israel." Moses opens with the same summons that frames the great commandment (6:4) and Israel\'s foundational confession. <em>Shema</em> (H8085) is more than hearing; it implies attentive obedience — "hear and do." The call to all of Israel (<em>kol-yiśrāʾēl</em>) stresses the covenant community as a whole, not merely its leaders.</p>',
    "2": '<p><strong>כָּרַת</strong> (<em>kārat</em>, H3772) — "cut a covenant": the standard Hebrew idiom for covenant-making, rooted in the sacrificial rite of cutting animals (Gen 15:10). The covenant was made <em>at Horeb</em> (the Deuteronomic name for Sinai), tying the legal content of chs. 5–26 to the historical event of the Exodus generation\'s encounter with YHWH.</p>',
    "3": '<p>The claim "not with our fathers but with us" resists covenant-as-inheritance in a passive sense. Every generation stands directly before YHWH as the covenant party. <em>Anachnu</em> (we) is emphatic: the covenant is not a legal artifact passed down but a living relation each generation must own. This logic drives Moses\'s renewal-preaching in Deuteronomy as a whole.</p>',
    "4": '<p><strong>פָּנִים בְּפָנִים</strong> (<em>pānîm bĕpānîm</em>) — "face to face": the most direct possible mode of divine communication. The same phrase describes Moses\'s unique prophetic access (34:10; Num 12:8). The people\'s experience at Sinai/Horeb — hearing the divine voice from fire — was not mediated by human intermediary at that moment; the mediation (v5) came because of their fear afterward.</p>',
    "5": '<p><strong>עָמַד בֵּין</strong> (<em>ʿāmad bên</em>) — "I stood between": Moses\'s intercessory position is both spatial (between the people and the divine fire) and covenantal (mediating word). The same verb root <em>ʿmd</em> describes the priest standing before YHWH to minister. Moses\'s role combines prophetic (declaring the word), priestly (standing between), and quasi-judicial (bringing YHWH\'s verdict to the people) functions.</p>',
    "6": '<p>The preamble to the Decalogue — "I am YHWH your God who brought you out" — precedes all commands. This is the standard suzerainty-treaty order: the great king identifies himself and cites his past benefactions before issuing stipulations. The commands that follow are responses to prior grace, not conditions for earning it. <em>Bêt ʿăbādîm</em> ("house of slavery") is Israel\'s pre-covenant identity; the commands define who the redeemed are now.</p>',
    "7": '<p><strong>עַל פָּנַי</strong> (<em>ʿal pānāy</em>) — traditionally "before me" but literally "against my face" or "to my face." The idiom may mean "in my presence" (no other gods where I am present, i.e., anywhere) or "in addition to me" (no gods as rivals). The spatial sense reinforces that the prohibition is not merely theoretical monotheism but relational exclusivity: the God who redeemed Israel will not share the covenant relationship.</p>',
    "8": '<p><strong>פֶּסֶל</strong> (<em>pesel</em>, H6459) — a graven/carved image; <strong>תְּמוּנָה</strong> (<em>tĕmûnāh</em>) — a likeness or form. The prohibition covers both making and possessing images. The scope is comprehensive: heaven above, earth beneath, waters under earth — the three tiers of the ancient cosmology. The concern is not merely idolatry toward foreign gods but any visual representation of YHWH himself (Deut 4:15-16: "you saw no form").</p>',
    "9": '<p><strong>אֵל קַנָּא</strong> (<em>ʾēl qannāʾ</em>) — "a jealous God." <em>Qannāʾ</em> (H7067) is used exclusively of YHWH in the OT and denotes the exclusive claim of the covenant relationship — not petty envy but the righteous intolerance of covenant violation. The "visiting iniquity of fathers on children" clause reflects corporate solidarity: covenant faithfulness (or unfaithfulness) has generational consequences. The contrast in v10 — "steadfast love to thousands" — shows the asymmetry: punishment extends to 3-4 generations; <em>ḥesed</em> extends to thousands.</p>',
    "10": '<p><strong>חֶסֶד</strong> (<em>ḥesed</em>, H2617) — steadfast love, covenantal loyalty. The contrast between the third-to-fourth generation of v9 and "thousands" here is deliberately asymmetric: divine judgment is limited and proportional; divine <em>ḥesed</em> is extensive and generous. The recipients are those who "love me and keep my commandments" — the covenant-loyal community. <em>Ḥesed</em> is not unconditional sentimentality but the faithfulness of a covenant partner who rewards the faithful.</p>',
    "11": '<p><strong>לַשָּׁוְא</strong> (<em>laššāwĕʾ</em>, H7723) — "for emptiness/worthlessness/falsehood." The prohibition covers not only profanity (using YHWH\'s name as a curse or oath-word) but invoking the divine name for empty, false, or deceptive purposes — swearing falsely, invoking YHWH to guarantee a lie, or treating the divine name as a magical formula. <em>Shāwĕʾ</em> has the semantic range of "vain," "worthless," "false" — the name of the living God is not to be wielded for worthless ends.</p>',
    "12": '<p><strong>שָׁמוֹר</strong> (<em>shāmôr</em>) — "observe, guard." In Exod 20:8, the command is <em>zākor</em> ("remember") the Sabbath. Deuteronomy substitutes "observe/guard" (<em>shāmôr</em>) — not a contradiction but a complementary nuance: Exodus ties Sabbath to creation-memory (God rested); Deuteronomy ties it to liberation-memory and the ethic of rest for all, including slaves (v14-15).</p>',
    "13": '<p>Six days of labor (<em>ʿāsîtā kol-mĕlākĕtekā</em>) are affirmed, not merely permitted: work is part of the created order and covenant faithfulness. The Sabbath is the seventh-day cessation from the six-day norm, not a replacement for it.</p>',
    "14": '<p>The Deuteronomic Sabbath extends rest explicitly to the <em>ben-amatkā</em> (your male slave) and <em>bat-amatkā</em> (female slave), and to the sojourner (<em>gēr</em>) within the gates. Exodus 20 lists the same beneficiaries but in a more compressed form. The humanitarian motivation — "so that your slave may rest as you do" — is characteristically Deuteronomic, grounding law in empathy rooted in Israel\'s own experience of servitude.</p>',
    "15": '<p><strong>זָכַרְתָּ כִּי עֶבֶד הָיִיתָ</strong> (<em>zākarttā kî ʿebed hāyîtā</em>) — "remember that you were a slave." The Sabbath in Deuteronomy is grounded in the Exodus, not creation (Exod 20:11). Memory of servitude becomes the ethical foundation for extending rest to those who serve. The "mighty hand and outstretched arm" (<em>yād ḥăzāqāh ûzĕrôaʿ nĕṭûyāh</em>) is a fixed formulaic pair for the Exodus event — it appears frequently in Deuteronomy as the experiential basis for covenant obligation.</p>',
    "16": '<p><strong>כַּבֵּד אֶת אָבִיךָ וְאֶת אִמֶּךָ</strong> (<em>kabbēd ʾet-ʾābîkā wĕʾet-ʾimmekā</em>): "Honor your father and your mother." <em>Kabbēd</em> (H3513, piel of כָּבַד) means to make heavy/weighty, i.e., to treat as significant and authoritative — not merely affection but social recognition of parental authority. The attached promise — "that your days may be long and that it may go well with you" — is the first commandment with a promise (Eph 6:2-3), and Paul cites it as still applicable to NT believers under a new framework.</p>',
    "17": '<p><strong>לֹא תִרְצָח</strong> (<em>lōʾ tirṣaḥ</em>): The verb <em>rāṣaḥ</em> (H7523) is not the general term for killing (<em>hārag</em> or <em>mût</em>) but the specific term for unlawful homicide — murder, manslaughter requiring legal process (Num 35:16-28). It does not prohibit all killing (capital punishment and holy war are commanded elsewhere); it prohibits the taking of human life outside the covenant community\'s authorized frameworks.</p>',
    "18": '<p><strong>לֹא תִנְאָף</strong> (<em>lōʾ tinʾāp</em>): <em>nāʾap</em> (H5003) — sexual betrayal of the covenant. The sexual act here is covenantally framed: marriage is the covenant between husband and wife; adultery violates both the human covenant and Israel\'s self-understanding as YHWH\'s covenant-spouse. The prophets use adultery as the primary image for Israel\'s idolatry (Hosea, Ezekiel) — the two transgressions share the same covenantal structure.</p>',
    "19": '<p><strong>לֹא תִגְנֹב</strong> (<em>lōʾ tignōb</em>): <em>gānab</em> (H1589) — to steal, but also to deceive or act covertly. Rabbinic tradition reads this commandment as prohibiting kidnapping (carrying a person off to slavery) rather than property theft, since property theft has its own specific legislation. On either reading, it protects the physical and social integrity of the covenant neighbor.</p>',
    "20": '<p><strong>עֵד שָׁוְא</strong> (<em>ʿēd shāwĕʾ</em>) — "a worthless/false witness." Deuteronomy uses <em>shāwĕʾ</em> (worthless/false) in place of Exodus 20:16\'s <em>šeqer</em> (lying). The distinction may be slight, but <em>shāwĕʾ</em> adds the nuance of testimony that is empty or groundless, not just deliberately false. Legal testimony in the covenant community carries divine weight; groundless accusation corrupts justice at its foundation.</p>',
    "21": '<p>Deuteronomy uses two different verbs in v21 where Exodus 20:17 uses one. For coveting a neighbor\'s wife: <strong>חָמַד</strong> (<em>ḥāmad</em>, H2530) — to delight in, to desire with pleasure. For coveting a neighbor\'s house, field, etc.: <strong>תִּתְאַוֶּה</strong> (<em>titʾawweh</em>, from אָוָה H183) — to wish for, to crave. The choice of two different verbs may distinguish relational desire (for a person) from acquisitive desire (for property), or may simply be stylistic variation. In either case, both forms of covetousness are prohibited as violations of the neighbor\'s whole life and estate.</p>',
    "22": '<p><strong>קוֹל גָּדוֹל</strong> (<em>qôl gādôl</em>) — "a great voice": the divine voice at Sinai/Horeb is a sustained, overwhelming auditory experience. <em>Welōʾ yāsāp</em> — "he did not add more," implying these ten words are the complete, sealed direct divine speech. The Decalogue is uniquely distinguished: written on stone by God, spoken directly to the whole assembly without human mediation. Everything else in the law came through Moses.</p>',
    "23": '<p>The elders and tribal heads (<em>rāʾšê šibṭêkem</em>) approach Moses — the leaders acting for the people as a whole. The "darkness" (<em>ḥōšek</em>) and "cloud" (<em>ʿānān</em>) are the typical theophanic veil: YHWH\'s presence manifests in phenomena that conceal as they reveal, protecting the people from the unmediated divine glory.</p>',
    "24": '<p><strong>כְּבֹדוֹ וְאֶת גָּדְלוֹ</strong> (<em>kĕbōdô wĕʾet-godlô</em>) — "his glory and greatness." <em>Kābôd</em> (H3519) is the weightiness, radiance, manifest importance of YHWH\'s presence; <em>gādal</em> (H1431) is the extensiveness of his power and works. The people\'s admission — "we have heard his voice from the fire" — confirms the unique standing of the Sinaitic theophany in Israel\'s history.</p>',
    "25": '<p>The people\'s fear of death if they continue to hear YHWH\'s voice directly becomes the occasion for Mosaic mediation. "This great fire will consume us" — the divine holiness is lethal to those without adequate standing before it. This is not pusillanimity but accurate anthropological assessment: the creature cannot sustain direct confrontation with uncreated holiness without a mediating structure.</p>',
    "26": '<p><strong>אֱלֹהִים חַיִּים</strong> (<em>ʾĕlōhîm ḥayyîm</em>) — "the living God": this title distinguishes YHWH from dead idols that cannot speak. The question "who among all flesh has ever heard the voice of the living God speaking from fire and lived?" marks the Sinai theophany as existentially unique. The answer is: only Israel, and they survived only through YHWH\'s mercy.</p>',
    "27": '<p><strong>דַּבֵּר אַתָּה</strong> (<em>dabbēr ʾattāh</em>) — "you speak to us." The people\'s delegation of hearing to Moses is the foundation of the prophetic institution. Moses as the covenant mediator becomes the pattern for all subsequent prophets, and ultimately for the prophet-like-Moses still to come (18:15). The people\'s request is honored: YHWH approves it (v28) and establishes Moses as the permanent mouthpiece.</p>',
    "28": '<p>YHWH\'s response — "they are right in all they have spoken" — validates the people\'s instinct. Their fear is not faithlessness; their delegation to Moses is appropriate. The divine approval of the mediatorial structure is significant: YHWH himself institutes the pattern of indirect revelation through a human spokesperson, which becomes the constitutive structure of the prophetic office.</p>',
    "29": '<p><strong>מִי יִתֵּן</strong> (<em>mî yittēn</em>) — the idiom of wishing: "O that they had such a heart as this always." The divine wish expresses genuine pathos: YHWH desires the people\'s sustained covenantal fidelity but recognizes they do not have the heart for it. This verse is the OT\'s sharpest pre-Jeremiah expression of the new covenant problem — external law without transformed heart is structurally insufficient. Jeremiah 31:33 and Ezekiel 36:26 will promise the solution: a new heart.</p>',
    "30": '<p>The command "return to your tents" disperses the assembly back to domestic life after the theophanic encounter. The juxtaposition with v31 ("but as for you, stand here with me") underscores Moses\'s unique station: Israel returns to ordinary life; Moses remains in the divine presence to receive the full law.</p>',
    "31": '<p><strong>אֶת כָּל הַמִּצְוָה</strong> (<em>ʾet kol-hammitsĕwāh</em>) — "the whole commandment." The singular <em>mitswāh</em> followed by the plural <em>ḥuqqîm ûmishpāṭîm</em> (statutes and rules) reflects Deuteronomy\'s structure: the one commandment (covenant loyalty) expressed in many stipulations. The law is a unity with a variegated expression.</p>',
    "32": '<p><strong>לֹא תְסוּרוּ יָמִין וּשְׂמֹאול</strong> (<em>lōʾ tāsûrû yāmîn ûśmōʾl</em>) — "do not turn aside to the right or to the left." This formula for covenant faithfulness — walking the exact path without deviation — recurs throughout Deuteronomy and the Deuteronomistic History. It becomes the criterion for evaluating the kings of Israel: did they walk in the ways of David, or did they turn aside?</p>',
    "33": '<p>The goal of covenant obedience is life: <em>lĕmaʿan tiḥyûn</em> ("so that you may live"). Deuteronomy is consistently shaped by the life-or-death stakes of covenant keeping. The choice will be formalized in 30:15-20 as the covenant\'s climax: life and good, or death and evil. Obedience is not the condition for earning life but the path within which covenant life is sustained.</p>'
  },
  "6": {
    "1": '<p><strong>הַמִּצְוָה הַחֻקִּים וְהַמִּשְׁפָּטִים</strong> (<em>hammitsĕwāh haḥuqqîm wĕhammishpāṭîm</em>) — the three categories of Deuteronomic law: the overarching commandment (<em>mitswāh</em>, covenant loyalty), the statutes (<em>ḥuqqîm</em>, ordinances without stated reason), and the rules (<em>mishpāṭîm</em>, case-law judgments). The singular <em>mitswāh</em> can function as a collective for the whole Torah or as the one great demand (love of YHWH, v5) that the rest expresses.</p>',
    "2": '<p><strong>לְיִרְאָה</strong> (<em>lĕyirʾāh</em>) — "to fear." <em>Yirʾāh</em> (H3374) in Deuteronomy encompasses both reverential awe and practical obedience — it is not mere terror but the posture of standing before a sovereign whose word is authoritative. The goal stated here — fear → keeping → long life — traces the covenant logic: the proper orientation toward YHWH produces the behavior that results in the flourishing promised in the covenant.</p>',
    "3": '<p>The summative appeal of v3 captures the Deuteronomic pattern: <em>shema</em> (hear/obey) → <em>shāmar</em> (keep/guard) → <em>ʿāśāh</em> (do). The three verbs together form a comprehensive call: receive, internalize, and enact. "That it may go well with you" (<em>ʾăšer yîṭab lāk</em>) ties obedience to covenant blessing — not as merit but as the natural ecology of the covenant relationship.</p>',
    "5": '<p><strong>וְאָהַבְתָּ אֵת יְהוָה אֱלֹהֶיךָ</strong> (<em>wĕʾāhavtā ʾēt Yhwh ʾĕlōhêkā</em>) — "you shall love the LORD your God." <em>Āhab</em> (H157) in a covenant context denotes not merely warm feeling but the committed loyalty of a covenant partner. The love required here is structured by three terms: <em>lĕbābĕkā</em> (your heart — the decision-making center and will), <em>napšĕkā</em> (your soul/life — the whole self, including emotions and vitality), and <em>mĕʾōdekā</em> (your might/abundance — all your resources and energy). Jesus cites this as the greatest commandment (Matt 22:37), adding "mind" (<em>dianoia</em>) which renders the Deuteronomic <em>lēb</em> in its full cognitive dimension. Together the three/four faculties form a merism: the entirety of human personhood is to be oriented toward YHWH.</p>',
    "6": '<p><strong>עַל לְבָבֶךָ</strong> (<em>ʿal lĕbābĕkā</em>) — "on your heart." The location of the commandment is the heart, not a stone tablet or scroll: internalizing precedes externalizing. This verse is the precursor to the new covenant promise of Jer 31:33 ("I will put my law on their hearts") — the Deuteronomic demand for heart-law becomes the covenantal goal that the Sinaitic system could specify but not guarantee.</p>',
    "7": '<p><strong>וְשִׁנַּנְתָּם</strong> (<em>wĕšinnantām</em>) — "you shall teach them diligently/sharpen them." The verb (H8150) has the nuance of incision — sharp, repeated instruction. The contexts of teaching listed — sitting, walking, lying down, rising — are the complete round of daily life. The Torah is not to be reserved for formal instruction but woven into every conversational moment.</p>',
    "8": '<p><strong>קְשַׁרְתָּם לְאוֹת</strong> (<em>qĕšartām lĕʾôt</em>) — "bind them as a sign on your hand." The command became the basis for the practice of tefillin (phylacteries) — small boxes containing Torah texts worn on the hand and forehead. Whether the original text intends the physical practice or a metaphor for constant Torah-mindedness (as Prov 3:3 uses similar language metaphorically) is debated. Jesus criticizes the Pharisaic expansion of the practice (Matt 23:5, "they make their phylacteries broad") without dismissing the underlying principle.</p>',
    "9": '<p><strong>מְזוּזוֹת</strong> (<em>mĕzûzôt</em>) — "doorposts." The <em>mezuzah</em> practice (affixing Torah texts to doorposts) arises from this command. The doorpost was already a covenantal marker from the Passover blood ritual (Exod 12:7, 22-23). Writing Torah on the gates frames the household as a covenant space: entering and leaving, the family passes under the sign of the covenant.</p>',
    "10": '<p>The transition from wilderness to settled land poses the chief Deuteronomic spiritual danger: prosperity-induced forgetting. "Houses filled with all good things that you did not fill" — the unearned abundance of the land is YHWH\'s gift, not Israel\'s achievement. The ethical danger of inherited blessing is the delusion of self-sufficiency.</p>',
    "11": '<p>The accumulation of unearned goods — "cisterns cut out that you did not cut, vineyards and olive trees that you did not plant" — forms the material backdrop for the warning of v12. This is the classic Deuteronomic prosperity trap: the blessings of covenant faithfulness can, paradoxically, generate the forgetfulness that breaks the covenant.</p>',
    "12": '<p><strong>פֶּן תִּשְׁכַּח</strong> (<em>pen tishkaḥ</em>) — "take care that you do not forget." The verb <em>shākaḥ</em> (H7911, to forget) is the negative counterpart to the constant Deuteronomic imperative to remember (<em>zākar</em>). Forgetting YHWH means losing the Exodus-identity that defines Israel as a people. Memory is not merely psychological but covenantal: to forget is to functionally deny the relationship.</p>',
    "13": '<p><strong>אֶת יְהוָה אֱלֹהֶיךָ תִּירָא וְאֹתוֹ תַעֲבֹד</strong> (<em>ʾet Yhwh ʾĕlōhêkā tîrāʾ wĕʾōtô taʿăbōd</em>) — "the LORD your God you shall fear, and him you shall serve." The emphatic word order places YHWH (<em>ʾōtô</em>) before the verbs — exclusive devotion: YHWH alone is to be feared and served. Jesus quotes this verse directly against Satan in the wilderness (Matt 4:10: "you shall worship the Lord your God, and him only shall you serve"), using <em>proskynēseis</em> (worship/bow down) for <em>tîrāʾ</em> and <em>latreuō</em> (serve/render religious service) for <em>taʿăbōd</em>.</p>',
    "14": '<p>The prohibition "do not go after other gods" (<em>lōʾ tēlĕkûn ʾaḥărê ʾĕlōhîm ʾăḥērîm</em>) uses the verb <em>hālak ʾaḥărê</em> (to walk after, to follow) — the language of personal allegiance and following a lord. Going after other gods is the covenantal equivalent of desertion.</p>',
    "15": '<p><strong>אֵל קַנָּא</strong> — jealous God (as in 5:9). The phrase "lest the anger of the LORD your God be kindled against you and he destroy you from the face of the earth" (<em>wĕhišmidĕkā mēʿal pĕnê hāʾădāmāh</em>) is the ultimate covenant sanction — exclusion from covenant life and from the land that is covenant existence. The stakes of covenant unfaithfulness are not merely behavioral correction but existential annihilation of the community.</p>',
    "16": '<p><strong>לֹא תְנַסּוּ</strong> (<em>lōʾ tĕnassû</em>) — "you shall not put to the test." <em>Nāsāh</em> (H5254) means to test or prove — to act as if YHWH\'s presence or power needs demonstration. "As you tested him at Massah" (Exod 17:1-7, where the people demanded water as proof of YHWH\'s presence) describes the paradigm: covenant testing demands proof before trusting. Jesus quotes this exact verse (Matt 4:7; Luke 4:12) against the devil\'s proposal to test YHWH by a staged fall requiring angelic rescue.</p>',
    "17": '<p><strong>שָׁמוֹר תִּשְׁמְרוּן</strong> (<em>shāmôr tišmĕrûn</em>) — the infinitive absolute with the finite verb: "diligently keep" (emphatic/intensive). The doubled verbal construction is characteristic of Deuteronomy\'s rhetorical emphasis; it heightens the urgency of observance beyond routine compliance to vigilant guarding.</p>',
    "18": '<p><strong>הַיָּשָׁר וְהַטּוֹב</strong> (<em>hayyāshār wĕhaṭṭôb</em>) — "the right and the good." This phrase goes beyond statutory compliance: "what is right and good in the sight of the LORD" is a moral category beyond mere legal conformity. Deuteronomy regularly supplements the legal corpus with this kind of character-orienting language, pointing to a disposition-level righteousness rather than merely a conduct-level compliance.</p>',
    "19": '<p>The goal of covenant obedience includes military and territorial consequences: thrusting out (<em>hădōp</em>) enemies as YHWH promised. The promise of land is covenantally conditioned — the people\'s fidelity is the channel through which YHWH\'s prior promise flows into realized inheritance.</p>',
    "20": '<p>The catechetical question — "what do these testimonies and statutes and rules mean?" — anticipates the next generation\'s need for covenant formation. The child\'s question is the occasion for the Exodus-recital (vv21-25): law is always explained by prior redemption. The statutory life of Israel is unintelligible apart from its Exodus origin. This pattern — law after narrative, command after grace — is the structure of Deuteronomy\'s ethics.</p>',
    "21": '<p><strong>עֲבָדִים הָיִינוּ לְפַרְעֹה</strong> (<em>ʿăbādîm hāyînû lĕparʿōh</em>) — "we were slaves to Pharaoh." The first-person plural encompasses every generation: the Exodus narrative is the community\'s constitutive story, not just ancient history. <em>Wayyōṣiʾēnû Yhwh</em> ("and YHWH brought us out") — the divine act of liberation precedes and generates the legal obligations of the covenant.</p>',
    "22": '<p>The Exodus signs and wonders (<em>ʾōtôt ûmôpĕtîm</em>) are the empirical foundation of the covenant\'s credibility. YHWH is not known abstractly but through observed, narrated historical action. The "great and terrible signs" do not generate belief as proof but provide the narrative content for a faith that is already constituted by covenant relationship.</p>',
    "23": '<p><strong>לְהָבִיא אֹתָנוּ</strong> (<em>lĕhābîʾ ʾōtānû</em>) — "to bring us in." The Exodus is not primarily an escape-from but a bringing-to: the goal is the land, not the wilderness. The liberation from Egypt has a telos — covenant life in the promised land — and the whole Torah is the charter for that life.</p>',
    "24": '<p><strong>לְיִרְאָה אֶת יְהוָה אֱלֹהֵינוּ</strong> (<em>lĕyirʾāh ʾet Yhwh ʾĕlōhênû</em>) — "to fear the LORD our God." The purpose of the statutes is not arbitrary obedience but the formation of the fear-of-YHWH that is the beginning of wisdom (Prov 9:10). "For our good always" (<em>lĕṭôb lānû kol-hayyāmîm</em>) — covenant law is not an imposition but a gift; the commandments are structurally oriented toward the community\'s flourishing.</p>',
    "25": '<p><strong>וּצְדָקָה תִּהְיֶה לָּנוּ</strong> (<em>ûṣĕdāqāh tihyeh lānû</em>) — "and it will be righteousness for us." <em>Ṣĕdāqāh</em> (H6666) here functions not as a forensic verdict but as a relational/ethical state: the community that keeps the covenant commandments stands in right relation (<em>ṣedeq</em>) with YHWH. This is not works-righteousness in a transactional sense; it is the description of what covenant faithfulness looks like from the inside. Paul\'s argument in Romans (esp. 10:5-6) distinguishes this righteousness of the law from the righteousness that is by faith, but both operate within the framework of covenant relation.</p>'
  },
  "7": {
    "1": '<p>The list of seven nations — Hittites, Girgashites, Amorites, Canaanites, Perizzites, Hivites, Jebusites — is the standard Deuteronomic enumeration of Canaan\'s pre-Israelite inhabitants. The number seven suggests completeness; these are all the peoples of the promised land. <em>Waḥărēm taḥărîm ʾōtām</em> ("you must completely destroy them") introduces the <em>ḥerem</em> (H2764) principle — consecrated/devoted destruction — which is theologically and historically one of the most demanding elements of Deuteronomy.</p>',
    "2": '<p><strong>חֵרֶם תַּחֲרִים</strong> (<em>ḥērem taḥărîm</em>) — the infinitive absolute intensifying: "you shall utterly devote to destruction." <em>Ḥērem</em> designates something removed from ordinary use and dedicated to YHWH, whether by destruction or consecration. In warfare, it means the complete removal of the enemy from the land without taking spoil, because the land itself belongs to YHWH and the inhabitants\' corruption is total. "You must not make a covenant (<em>lōʾ tikrōt lāhem bĕrît</em>) with them" — covenant-making is the opposite of <em>ḥērem</em>; it would assimilate Israel to the very idolatry it must purge.</p>',
    "3": '<p>The intermarriage prohibition is grounded in v4: the danger is not ethnic contamination but theological assimilation. "They will turn your sons away from following me to serve other gods" — the household becomes the entry point for covenant unfaithfulness. The prohibition is directional: the problem is not the foreign person but the foreign worship they would introduce.</p>',
    "4": '<p>The causal chain: intermarriage → turning your sons → serving other gods → YHWH\'s anger → swift destruction. The speed of the sanction (<em>mĕhēr</em>, quickly) reflects Deuteronomy\'s concern that covenant apostasy does not have a long runway — once the heart has turned, the consequences follow.</p>',
    "5": '<p>The commanded destruction of Canaanite religious infrastructure — altars (<em>mizbĕḥōtāyhem</em>), sacred pillars (<em>maṣṣĕbōtām</em>), Asherah poles (<em>ʾăshērāyw</em>), and carved images (<em>pĕsîlêhem</em>) — is a systematic elimination of the material culture of Canaanite religion. These objects represent the rival system that would compete for Israel\'s covenantal allegiance. The positive command — "burn the carved images with fire" (v25) — makes clear that the destruction is itself a liturgical act of covenantal purification.</p>',
    "6": '<p><strong>סְגֻלָּה</strong> (<em>sĕgullāh</em>, H5459) — "treasured possession." The root suggests wealth closely guarded; it appears in Mal 3:17 ("they shall be mine, says the LORD of Hosts, my special possession"), Ps 135:4, and 1 Pet 2:9 (where Peter applies it to the NT church: "a people for his own possession," <em>laos eis peripoiēsin</em>). <em>Sĕgullāh</em> is Israel\'s most intimate covenantal title — not merely God\'s people but his personally treasured possession, set apart from all peoples of the earth.</p>',
    "7": '<p><strong>לֹא מֵרֻבְּכֶם</strong> (<em>lōʾ mērubbĕkem</em>) — "not because you were more numerous." The negative election theology here is rare in world religions: Israel is chosen not because of size, strength, or virtue but despite being the least of peoples (<em>haqqāṭōn mikkol hāʿammîm</em>). This undercuts all ethnic pride and establishes election as pure divine initiative.</p>',
    "8": '<p><strong>מֵאַהֲבַת יְהוָה אֶתְכֶם</strong> (<em>mēʾahăbat Yhwh ʾetkem</em>) — "because the LORD loved you." The reason for election is YHWH\'s own love (<em>ʾahăbāh</em>, H160) — a circular, irreducible reason: YHWH loves Israel because he loves Israel (cf. Deut 10:15). The second reason — keeping the oath sworn to the fathers — grounds the love in covenant faithfulness across generations. Both reasons are internal to YHWH\'s character, not external to Israel\'s merit.</p>',
    "9": '<p><strong>הָאֵל הַנֶּאֱמָן שֹׁמֵר הַבְּרִית וְהַחֶסֶד</strong> (<em>hāʾēl hanneʾĕmān shōmēr habbĕrît wĕhaḥesed</em>) — "the faithful God who keeps covenant and steadfast love." Three terms define YHWH\'s covenantal character: <em>neʾĕmān</em> (faithful, trustworthy, H539), <em>bĕrît</em> (covenant, H1285), <em>ḥesed</em> (steadfast love/loyalty, H2617). Together they describe a God whose commitment to the covenant relationship is structurally reliable — not capriciously revoked by Israel\'s failures but faithfully maintained. "To a thousand generations" (<em>lĕʾelep dôr</em>) is the eschatological horizon of covenant faithfulness.</p>',
    "10": '<p>The balancing clause: YHWH "repays those who hate him to their face" (<em>mĕšallēm lĕśōnĕʾāyw ʾel-pānāyw lĕhaʾăbîdô</em>). The divine faithfulness in v9 is matched by a corresponding divine righteousness — YHWH does not ignore those who hate him. The covenant has two faces: blessing for the faithful, sanction for the hostile. "He will not delay" (<em>lōʾ yĕʾaḥēr</em>) — the divine patience has limits with those who actively oppose the covenant.</p>',
    "11": '<p>The conclusion of the "faithful God" section (vv7-11): "therefore keep the commandments, statutes, and rules." The indicative of divine election and faithfulness (vv7-10) grounds the imperative of human obedience (v11). The logic is always this order: who YHWH is and what he has done → what Israel is to do. Command follows grace.</p>',
    "12": '<p><strong>עֵקֶב</strong> (<em>ʿēqeb</em>, H6118) — "because of, as a result of." The term can mean "heel" (the track of the heel, hence the consequence of walking in a certain path). The covenant blessings follow Israel\'s obedience as the track follows the foot — not because obedience earns blessing but because walking the covenant path leads through covenant blessing. <em>Shāmar</em> (to keep) + <em>ḥāsēd</em> (YHWH\'s loyal love) — the correspondence of human keeping and divine keeping is the covenant\'s relational structure.</p>',
    "13": '<p><strong>וְאֵהֵבְךָ וּבֵרַכְךָ וְהִרְבֶּךָ</strong> (<em>wĕʾēhēbĕkā ûbēraḵĕkā wĕhirbĕkā</em>) — "he will love you, bless you, and multiply you." Three verbs of divine action flowing from covenant faithfulness: love (prior commitment renewed in blessing), bless (material and social flourishing), multiply (generational continuity). The blessings listed — womb, ground, grain, wine, oil, herd, flock — are the fundamental fertility goods of agricultural life.</p>',
    "14": '<p><strong>בָּרוּךְ תִּהְיֶה מִכָּל הָעַמִּים</strong> (<em>bārûk tihyeh mikkol hāʿammîm</em>) — "blessed more than all peoples." The comparative "more than" (<em>mikkol</em>) situates Israel\'s covenant blessing in the context of the nations. This is not ethnocentrism but covenant distinctiveness: the people chosen to bear the divine name will be visibly blessed as a sign of YHWH\'s faithfulness — which is itself the means of the nations eventually coming to know him.</p>',
    "15": '<p><strong>מַחֲלֶה מִצְרַיִם</strong> (<em>maḥăleh miṣrāyim</em>) — "the diseases of Egypt." The covenant guarantee includes freedom from the diseases that afflicted Egypt — likely including the plagues but also the endemic diseases of the Nile region. YHWH\'s healing protection is the positive counterpart to the military protection of holy war.</p>',
    "16": '<p><strong>וְלֹא תַחוֹס עֵינְךָ עֲלֵיהֶם</strong> (<em>wĕlōʾ tāḥôs ʿênĕkā ʿălêhem</em>) — "do not look on them with pity." <em>Ḥûs</em> (H2347) means to have regard for, to spare emotionally. The prohibition against emotional pity toward the nations targeted for <em>ḥērem</em> is not cruelty but the recognition that sentiment-driven compromise would undermine the very purpose of the conquest: not expelling the false worship from the land. "And do not serve their gods — for that would be a snare to you": the warning is ultimately self-protective, not triumphalist.</p>',
    "17": '<p>The rhetorical question "these nations are more powerful than I" is addressed before the emotion arises. Deuteronomy consistently anticipates the fear and doubt that will arise when Israel faces the militarily superior nations of Canaan and provides the corrective before the crisis comes.</p>',
    "18": '<p><strong>זָכֹר תִּזְכֹּר</strong> (<em>zākōr tizzĕkōr</em>) — infinitive absolute + finite verb: "remember carefully/diligently." Memory of what YHWH did to Pharaoh and Egypt is the antidote to fear of the Canaanite nations. The Exodus is not ancient history but the ongoing credential of the God who fights for Israel.</p>',
    "19": '<p><strong>הַמַּסֹּת הַגְּדֹלֹת אֲשֶׁר רָאוּ עֵינֶיךָ</strong> (<em>hammassōt haggĕdōlōt ʾăsher rāʾû ʿênêkā</em>) — "the great ordeals your eyes saw." The appeal is to eyewitness testimony: the signs, wonders, mighty hand, and outstretched arm are not mythology but narrated history to which the living generation can testify. This empirical grounding of faith is characteristic of Deuteronomy\'s rhetorical strategy.</p>',
    "20": '<p><strong>הַצִּרְעָה</strong> (<em>haṣṣirʿāh</em>) — "the hornet." The divine hornet sent among the survivors is a mysterious reference — possibly the Egyptian military campaigns that weakened the Canaanites before Israel\'s arrival, or a literal insect agent (as in Exod 23:28; Josh 24:12), or a metaphor for divine panic-inducing judgment. Whatever the referent, it represents YHWH\'s own initiative supplementing Israel\'s military effort: the conquest is jointly divine-human.</p>',
    "21": '<p><strong>אֵל גָּדוֹל וְנוֹרָא</strong> (<em>ʾēl gādôl wĕnôrāʾ</em>) — "a great and awesome God." <em>Nôrāʾ</em> (H3372, the Niphal participle of <em>yārēʾ</em>, to fear) means fear-inducing, awesome in the sense of evoking reverent dread. The phrase recurs in Neh 1:5; 9:32 and Dan 9:4 — a liturgical formula for the God who is terrifying in power and faithful in covenant.</p>',
    "22": '<p>The "little by little" (<em>mĕʿaṭ mĕʿaṭ</em>) conquest strategy reflects ecological wisdom: complete and immediate depopulation would leave the land to wild animals. The divine timing is not weakness but prudent management of a complex transition. This pragmatic note within the theology of holy war is characteristic of Deuteronomy\'s realistic ethical vision.</p>',
    "23": '<p><strong>מְהוּמָה גְדֹלָה</strong> (<em>mĕhûmāh gĕdōlāh</em>) — "great panic/confusion." <em>Mĕhûmāh</em> (H4103) is the divinely-sent panic that immobilizes the enemy, making military defeat possible. The same term appears in the description of divine warfare throughout the OT (1 Sam 14:15; Zech 14:13). It is YHWH\'s weapon before Israel strikes: the conquest is YHWH\'s victory first, Israel\'s second.</p>',
    "24": '<p><strong>מָחָה אֶת שְׁמָם</strong> (<em>māḥāh ʾet šĕmām</em>) — "erase their name." The erasure of a name from "under heaven" is the reversal of covenant existence: to have a name is to have continuing presence and legacy; to have one\'s name erased is complete covenant annihilation. This is the ultimate <em>ḥērem</em> sanction.</p>',
    "25": '<p><strong>פְּסִילֵי אֱלֹהֵיהֶם תִּשְׂרְפוּן בָּאֵשׁ</strong> (<em>pĕsîlê ʾĕlōhêhem tisrĕpûn bāʾēsh</em>) — "burn the carved images of their gods with fire." The fire-destruction of idols is the inverse of YHWH\'s theophanic fire: the divine fire that spoke from Horeb now destroys the images that would rival YHWH. <em>Tôʿēbāh lYhwh</em> ("a detestable thing to the LORD") — the same term (<em>tôʿēbāh</em>, H8441, abomination) used for Israel\'s dietary prohibitions and sexual violations: idols belong to the same category of covenant-contaminating objects.</p>',
    "26": '<p><strong>חֵרֶם תִּהְיֶה כָּמֹהוּ</strong> (<em>ḥērem tihyeh kāmōhû</em>) — "you will be devoted to destruction along with it." The principle of contamination-by-association: bringing a <em>ḥērem</em>-object into the household transfers the <em>ḥērem</em> status to the household. This is not magic but covenantal reality: the object that belongs to YHWH for destruction cannot be assimilated to the covenant community without destroying that community. The story of Achan (Josh 7) is the narrative demonstration of this principle.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'deuteronomy')
    merge_comm(existing, DEUTERONOMY)
    save_comm('mkt-original', 'deuteronomy', existing)
    print('Deuteronomy 5-7 mkt-original written.')

if __name__ == '__main__':
    main()
